class Solution:
    def frequencySort(self, s: str) -> str:
        from collections import Counter
        count = Counter(s)
        freq = sorted(count.items(), key=lambda x: x[1], reverse=True)
        res = ''
        for char, freq in freq:
            res += char * freq
        return res
